using ChatGPTImageOrchestrator.Domain.Entities; using ChatGPTImageOrchestrator.Domain.Enums; using ChatGPTImageOrchestrator.Domain.Interfaces; using Microsoft.EntityFrameworkCore; namespace ChatGPTImageOrchestrator.Infrastructure.Persistence.Repositories;
public class AccountRepository(AppDbContext db):IAccountRepository{ public Task<GeneratorAccount?> GetNextActiveAsync(CancellationToken ct)=>db.Accounts.Where(x=>x.Status==AccountStatus.Active).OrderByDescending(x=>x.LastUsedDate).FirstOrDefaultAsync(ct); public async Task UpdateAsync(GeneratorAccount account,CancellationToken ct){db.Accounts.Update(account); await db.SaveChangesAsync(ct);} }
public class ProjectRepository(AppDbContext db):IProjectRepository{ public async Task AddAsync(GenerationProject project,CancellationToken ct){db.Projects.Add(project); await db.SaveChangesAsync(ct);} public Task<GenerationProject?> GetByIdAsync(Guid id,CancellationToken ct)=>db.Projects.FirstOrDefaultAsync(x=>x.Id==id,ct); public async Task UpdateAsync(GenerationProject project,CancellationToken ct){db.Projects.Update(project); await db.SaveChangesAsync(ct);} }
public class ImageTaskRepository(AppDbContext db):IImageTaskRepository{ public Task<ImageTask?> GetNextPendingAsync(CancellationToken ct)=>db.ImageTasks.Where(x=>x.Status==ImageTaskStatus.Queued||x.Status==ImageTaskStatus.RetryPending).OrderBy(x=>x.Id).FirstOrDefaultAsync(ct); public async Task<IReadOnlyList<ImageTask>> GetByProjectIdAsync(Guid projectId,CancellationToken ct)=>await db.ImageTasks.Where(x=>x.ProjectId==projectId).ToListAsync(ct); public async Task UpdateAsync(ImageTask task,CancellationToken ct){db.ImageTasks.Update(task); await db.SaveChangesAsync(ct);} }
